function ThreeColumnBrowser({ folders, items, selectedFolder, selectedItem, onSelectFolder, onSelectItem }) {
  const { div, main, header, span, nav, section, p } = tags;
  const [navCollapsed, setNavCollapsed] = createSignal(false);

  return div({ class: css('_grid _h[100vh]'), style: () => `grid-template-columns:${navCollapsed() ? '56px' : '220px'} 320px 1fr;grid-template-rows:52px 1fr` },
    // Header
    header({ class: css('_flex _aic _jcsb _px4 _borderB _bgbg'), style: 'grid-column:1/4' },
      div({ class: css('_flex _aic _gap3') },
        span({ class: css('_heading4') }, 'Browser'),
        div({ class: css('_flex _aic _gap2 _px3 _py1 _r2 _bgmuted') },
          icon('search'), span({ class: css('_fgmuted _textsm') }, 'Search...')
        )
      ),
      div({ class: css('_flex _aic _gap2') },
        Button({ variant: 'ghost', size: 'sm' }, icon('settings')),
        Avatar({ size: 'sm' })
      )
    ),
    // Nav tree
    nav({ class: css('_flex _col _borderR _bgmuted _overflow[auto] _p2') },
      div({ class: css('_flex _aic _jcsb _p3 _borderB') },
        !navCollapsed() ? span({ class: css('_fontmedium _textsm _fgmuted') }, 'Folders') : null,
        Button({ variant: 'ghost', size: 'sm', onclick: () => setNavCollapsed(!navCollapsed()) },
          icon('panel-left')
        )
      ),
      div({ class: css('_flex _col _gap[2px] _p2 _flex1 _overflow[auto]') },
        ...folders.map(f =>
          div({
            class: css(`_flex _aic _gap2 _p2 _r2 _cursor[pointer] _trans ${f.id === selectedFolder() ? '_bgactive _fgactive' : ''}`),
            onclick: () => onSelectFolder(f.id)
          },
            icon(f.icon || 'folder'),
            !navCollapsed() ? span({ class: css('_textsm _truncate') }, f.name) : null
          )
        )
      ),
      div({ class: css('_p2 _borderT') },
        Button({ variant: 'ghost', size: 'sm', class: css('_wfull') },
          icon('plus'), !navCollapsed() ? ' Add Folder' : null
        )
      )
    ),
    // Item list
    section({ class: css('_flex _col _borderR _overflow[auto]') },
      div({ class: css('_flex _aic _jcsb _px4 _py3 _borderB') },
        span({ class: css('_fontmedium _textsm') }, `${items().length} items`),
        Button({ variant: 'ghost', size: 'sm' }, icon('arrow-up-down'))
      ),
      div({ class: css('_flex _col _flex1 _overflow[auto]') },
        ...items().map(item =>
          div({
            class: css(`_px4 _py3 _borderB _cursor[pointer] _trans ${item.id === selectedItem() ? '_bgactive' : ''}`),
            onclick: () => onSelectItem(item.id)
          },
            span({ class: css('_fontmedium _textsm _block') }, item.title),
            span({ class: css('_textsm _fgmuted _truncate _block _mt1') }, item.preview),
            span({ class: css('_textxs _fgmuted _mt1') }, item.date)
          )
        )
      )
    ),
    // Detail preview
    main({ class: css('_flex _col _flex1 _overflow[auto] _p6') },
      selectedItem()
        ? div({},
            div({ class: css('_flex _aic _jcsb _pb4 _borderB') },
              span({ class: css('_heading4') }, items().find(i => i.id === selectedItem())?.title),
              div({ class: css('_flex _aic _gap2') },
                Button({ variant: 'ghost', size: 'sm' }, icon('reply')),
                Button({ variant: 'ghost', size: 'sm' }, icon('archive')),
                Button({ variant: 'ghost', size: 'sm' }, icon('trash'))
              )
            ),
            div({ class: css('_pt4') },
              p({}, items().find(i => i.id === selectedItem())?.content)
            )
          )
        : div({ class: css('_flex _col _aic _jcc _flex1 _fgmuted') },
            icon('inbox', { size: 48 }),
            p({ class: css('_mt4 _textsm') }, 'Select an item to view')
          )
    )
  );
}
